  // Fires for errors on IDLE clients in the pool, not on active queries
  console.error('Unexpected error on idle PostgreSQL client', err);
  // Do NOT exit the process here — the pool will remove the bad client
  // and create a new one on the next request.
});

pool.on('connect', (client) => {
  // Optional: runs when a new physical connection is established
  // e.g. set a session parameter
  // client.query('SET search_path TO myschema');
});
```

